display int errorsImage()
{
    int ret;

    switch (this.Status)
    {
        case IFRUniversalInterfaceSystemStatus::Error:
            ret = this.ErrorLogContainer != conNull() ? 929 : 0;
            break;
        case IFRUniversalInterfaceSystemStatus::Posted:
            ret = 1306;
            break;
        default:
            ret = 0;
            break;
    }       

    return ret;
}

public void writeInfoLogErrorData(str _errorStr = '')
{
    InfologData     infoLogData;
    SysInfoLogStr   sysInfologStr;

    if (_errorStr)
    {
        Error(_errorStr);
    }

    infologData		= infolog.infologData();
    SysInfoLogStr   = this.logText(infologData);

    if (infologData != conNull())
    {
        guid    nullGuid;

        ttsBegin;            
        this.selectForUpdate(true);

        this.ExecutionId        = nullGuid;
        this.ErrorLogContainer	= infologData;
        this.ErrorsLog			= SysInfoLogStr;
        this.Status	            = IFRUniversalInterfaceSystemStatus::Error;
        this.update();
        ttsCommit;
    }

    infolog.clear();
}

SysInfoLogStr logText(InfologData       _InfologData)
{
    #Define.NewLine('\n')

    SysInfoLogStr           logText;
    str                     logStr;
    Counter                 i;
    int                     p;
    SysInfologEnumerator    sysInfologEnumerator;
    SysInfologMessageStruct infoMessageStruct;

    if (_InfologData)
    {
        sysInfologEnumerator = SysInfologEnumerator::newData(_InfologData);
        while (sysInfologEnumerator.moveNext())
        {
            if (logText)
            {
                logText += #Newline;
            }

            logStr = '';
            infoMessageStruct = SysInfologMessageStruct::construct(sysInfologEnumerator.currentMessage());

            p = infoMessageStruct.prefixDepth();
            for (i = 1; i <= p; i++)
            {
                logStr += infoMessageStruct.preFixTextElement(i) + '. ';
            }
            logStr += infoMessageStruct.message();

            logStr = strLRTrim(logStr);
            logText += logStr;
        }
    }

    return logText;
}

public static void markRecordsAsProcessed(IFRUniversalInterfaceSystemExecutionId _ifrUniversalInterfaceSystemExecutionId,
                                                    RecId                               _recId)
{
    IFRUniversalInterfaceSystemTable ifrUniversalInterfaceSystemTable;

    update_recordset ifrUniversalInterfaceSystemTable
        setting Status              = IFRUniversalInterfaceSystemStatus::Posted,
                ErrorLogContainer   = conNull(),
                ErrorsLog           = ''
        where ifrUniversalInterfaceSystemTable.ExecutionId  == _ifrUniversalInterfaceSystemExecutionId
            && ifrUniversalInterfaceSystemTable.RecId       == _recId;

}

static IFRUniversalInterfaceSystemTable findRecId(RecId    _recId,
                           boolean  _forUpdate = false)
{
    IFRUniversalInterfaceSystemTable ifrUniversalInterfaceSystemTable;

    if (_recId)
    {
        ifrUniversalInterfaceSystemTable.selectForUpdate(_forUpdate);

        select firstonly ifrUniversalInterfaceSystemTable
            where ifrUniversalInterfaceSystemTable.RecId == _recId;
    }

    return ifrUniversalInterfaceSystemTable;
}
